#include<bits/stdc++.h>
using namespace std;

const int N = 1e5 + 5, M = 1e5 + 5;
int n, m, ans = -2e9;
vector<int> e[M];
int in[N], topo[N], dp[N], In[N], dp2[N];

bool toposort()
{
	int t = 0;
	queue<int> q;
	for(int i = 1; i <= n; i++)
		if(!in[i]) q.push(i);
	while(!q.empty())
	{
		int u = q.front();
		q.pop();
		topo[++t] = u;
		for(int v : e[u])
		{
			in[v]--;
			if(!in[v]) q.push(v);
		}
	}
	return t == n;
}

int main()
{
	cin >> n;
	for(int i = 1; i < n; i++)
	{
		int u, v;
		cin >> u >> v;
		e[u].push_back(v);
		in[v]++;
		In[v]++;
	}
	toposort();
	for(int i = n; i >= 1; --i)
	{
		int u = topo[i];
		dp[u]++;
		for(int v : e[u])
			dp[u] += dp[v];
	}
	for(int i = 1; i <= n; i++)
	{
		int u = topo[i];
		dp2[u]++;
		for(int v : e[u])
			dp2[v] += dp2[u];
	}
	for(int i = 1; i <= n; i++)
		if(In[i] && dp[i] + dp2[i] == n + 1) cout << i << endl;
	return 0;
}
